function peak_index(nums) {
    let lo=0, hi=nums.length-1;
    while (lo<hi) { const mid=(lo+hi)>>1; if (nums[mid]<nums[mid+1]) lo=mid+1; else hi=mid; }
    return lo;
}

function collatz(n) {
    let steps = 0; let x = n;
    while (x !== 1) { if (x % 2 === 0) x = x/2; else x = 3*x+1; steps++; }
    return steps;
}

function daily_temperatures(temps) {
    const n = temps.length; const out = new Array(n).fill(0); const stack = [];
    for (let i=0;i<n;i++) {
        while (stack.length && temps[stack[stack.length-1]] < temps[i]) { const j = stack.pop(); out[j] = i-j; }
        stack.push(i);
    }
    return out;
}

function find_duplicate(nums) {
    const seen = new Set();
    for (const x of nums) { if (seen.has(x)) return x; seen.add(x); }
    return -1;
}

function bfs(adj, src, n) {
    const dist = new Array(n).fill(-1); dist[src] = 0;
    const q = [src]; let qi = 0;
    while (qi < q.length) {
        const u = q[qi]; qi++;
        for (const v of adj[u]) { if (dist[v] === -1) { dist[v] = dist[u] + 1; q.push(v); } }
    }
    return dist;
}

function intersection(nums1, nums2) {
    const s1 = new Set(nums1), s2 = new Set(nums2);
    const out = [...s1].filter(x => s2.has(x)).sort((a,b)=>a-b);
    return out;
}

function largest_rectangle_area(heights) {
    const stack=[]; let best=0; const n=heights.length;
    for (let i=0;i<=n;i++) {
        const h = i===n ? 0 : heights[i];
        while (stack.length && heights[stack[stack.length-1]]>=h) {
            const top=stack.pop();
            const width = stack.length===0 ? i : i-stack[stack.length-1]-1;
            best = Math.max(best, heights[top]*width);
        }
        stack.push(i);
    }
    return best;
}

function longest_palindrome(s) {
    if (s.length===0) return 0;
    let best=1;
    function expand(l,r) { while (l>=0 && r<s.length && s[l]===s[r]) { l--; r++; } return r-l-1; }
    for (let i=0;i<s.length;i++) {
        best=Math.max(best, expand(i,i));
        best=Math.max(best, expand(i,i+1));
    }
    return best;
}

function majority_element(nums) {
    let count = 0, candidate = 0;
    for (const x of nums) { if (count === 0) candidate = x; count += (x === candidate) ? 1 : -1; }
    return candidate;
}

function max_subarray_sum_circular(nums) {
    let total=0, curMax=0, best=-Infinity, curMin=0, worst=Infinity;
    for (const x of nums) {
        total+=x;
        curMax=Math.max(curMax+x,x); best=Math.max(best,curMax);
        curMin=Math.min(curMin+x,x); worst=Math.min(worst,curMin);
    }
    if (best<0) return best;
    return Math.max(best, total-worst);
}

function miller_rabin(n) {
    if (n<2) return false;
    if (n<4) return true;
    if (n%2===0) return false;
    for (let i=3;i*i<=n;i+=2) if (n%i===0) return false;
    return true;
}

