function min_cut(s) {
    const n=s.length;
    const isPal = Array.from({length:n}, () => new Array(n).fill(false));
    for (let i=0;i<n;i++) isPal[i][i]=true;
    for (let len=2;len<=n;len++) {
        for (let i=0;i+len-1<n;i++) {
            const j=i+len-1;
            if (s[i]===s[j] && (len===2 || isPal[i+1][j-1])) isPal[i][j]=true;
        }
    }
    const dp=new Array(n).fill(0);
    for (let i=0;i<n;i++) {
        if (isPal[0][i]) { dp[i]=0; continue; }
        dp[i]=i;
        for (let j=1;j<=i;j++) if (isPal[j][i] && dp[j-1]+1<dp[i]) dp[i]=dp[j-1]+1;
    }
    return dp[n-1];
}

function product_except_self(nums) {
    const n = nums.length; const out = new Array(n).fill(1);
    let prefix = 1;
    for (let i=0;i<n;i++) { out[i] = prefix; prefix *= nums[i]; }
    let suffix = 1;
    for (let i=n-1;i>=0;i--) { out[i] *= suffix; suffix *= nums[i]; }
