function top_k_frequent(nums, k) {
    const freq = {};
    for (const x of nums) freq[x] = (freq[x]||0) + 1;
    const keys = Object.keys(freq).map(Number);
    keys.sort((a,b) => freq[b]-freq[a] || a-b);
    return keys.slice(0,k);
