function is_anagram(s, t) {
    if (s.length !== t.length) return false;
    const count = {};
    for (const ch of s) count[ch] = (count[ch]||0) + 1;
    for (const ch of t) { count[ch] = (count[ch]||0) - 1; if (count[ch] < 0) return false; }
    return Object.values(count).every(v => v === 0);
}
